   350→        &mut self,
   351→        data: &[u8],
   352→        ctx: &DecodeContext,
   353→    ) -> Result<Vec<DebugEvent>, CoreError> {
   354→        // Process data through HTTP/2 codec
   355→        let h2_events = self
   356→            .h2_codec
   357→            .process(data)
   358→            .map_err(|e| CoreError::PayloadDecode(e.to_string()))?;
   359→
