     1→//! Custom HTTP/2 frame parser with graceful HPACK degradation.
     2→//!
     3→//! This module provides HTTP/2 frame parsing for offline PCAP analysis with
     4→//! support for all frame types and HPACK encoding formats. It implements
     5→//! graceful degradation for mid-stream captures where HPACK dynamic table
     6→//! context is unavailable.
     7→
     8→use crate::error::GrpcError;
     9→use bytes::Bytes;
    10→use std::collections::HashMap;
    11→
    12→/// HTTP/2 stream state.
    13→#[derive(Debug)]
    14→pub struct StreamState {
    15→    /// Request headers (method, authority, path, etc.).
    16→    pub request_headers: HashMap<String, String>,
    17→    /// Response headers.
    18→    pub response_headers: HashMap<String, String>,
    19→    /// Trailing headers (grpc-status, grpc-message).
    20→    pub trailers: HashMap<String, String>,
    21→    /// Whether the stream has seen the initial request headers.
    22→    pub saw_request_headers: bool,
    23→    /// Whether the stream has seen response headers.
    24→    pub saw_response_headers: bool,
    25→    /// Whether the stream is closed.
    26→    pub closed: bool,
    27→}
    28→
    29→impl StreamState {
    30→    fn new() -> Self {
    31→        Self {
    32→            request_headers: HashMap::new(),
    33→            response_headers: HashMap::new(),
    34→            trailers: HashMap::new(),
    35→            saw_request_headers: false,
    36→            saw_response_headers: false,
    37→            closed: false,
    38→        }
    39→    }
    40→}
    41→
    42→/// HTTP/2 event parsed from the stream.
    43→#[derive(Debug)]
    44→pub enum H2Event {
    45→    /// HEADERS frame received.
    46→    Headers {
    47→        stream_id: u32,
    48→        headers: HashMap<String, String>,
    49→        end_stream: bool,
    50→    },
    51→    /// DATA frame received.
    52→    Data {
    53→        stream_id: u32,
    54→        data: Bytes,
    55→        end_stream: bool,
    56→    },
    57→    /// SETTINGS frame received.
    58→    Settings,
    59→    /// RST_STREAM frame received.
    60→    RstStream { stream_id: u32 },
    61→    /// GOAWAY frame received.
    62→    GoAway,
    63→    /// HPACK degradation warning.
    64→    HpackDegraded { reason: String },
    65→}
    66→
    67→/// HTTP/2 codec for parsing frames from a byte stream.
    68→pub struct H2Codec {
    69→    /// Per-stream state tracking.
    70→    streams: HashMap<u32, StreamState>,
    71→    /// Buffer for accumulating partial frames.
    72→    buffer: Vec<u8>,
    73→    /// Whether HPACK degradation has occurred.
    74→    hpack_degraded: bool,
    75→    /// Preface sent flag (HTTP/2 connection preface).
    76→    preface_seen: bool,
    77→    /// Buffer for accumulating header block fragments (HEADERS + CONTINUATION).
    78→    header_block_buffer: Option<(u32, Vec<u8>, bool)>, // (stream_id, buffer, end_stream)
    79→}
    80→
    81→impl H2Codec {
    82→    /// Create a new HTTP/2 codec.
    83→    pub fn new() -> Self {
    84→        Self {
    85→            streams: HashMap::new(),
    86→            buffer: Vec::new(),
    87→            hpack_degraded: false,
    88→            preface_seen: false,
    89→            header_block_buffer: None,
    90→        }
    91→    }
    92→
    93→    /// Process a chunk of bytes and return parsed events.
    94→    ///
    95→    /// This method feeds bytes into the HTTP/2 frame parser and returns
    96→    /// zero or more events. Partial frames are buffered internally.
    97→    pub fn process(&mut self, data: &[u8]) -> Result<Vec<H2Event>, GrpcError> {
    98→        // For now, implement a basic frame parser
    99→        // TODO: Replace with h2-sans-io integration when API is confirmed
   100→
   101→        self.buffer.extend_from_slice(data);
   102→        let mut events = Vec::new();
   103→
   104→        // Parse HTTP/2 connection preface if not seen yet
   105→        if !self.preface_seen && self.buffer.len() >= 24 {
   106→            const PREFACE: &[u8] = b"PRI * HTTP/2.0\r\n\r\nSM\r\n\r\n";
   107→            if self.buffer.starts_with(PREFACE) {
   108→                self.buffer.drain(0..24);
   109→                self.preface_seen = true;
   110→            }
   111→        }
   112→
   113→        // Parse frames
   114→        while self.buffer.len() >= 9 {
   115→            // HTTP/2 frame header: 9 bytes
   116→            // - 3 bytes: length (24-bit big-endian)
   117→            // - 1 byte: type
   118→            // - 1 byte: flags
   119→            // - 4 bytes: stream ID (31-bit, reserved bit must be 0)
   120→
   121→            let length = u32::from_be_bytes([0, self.buffer[0], self.buffer[1], self.buffer[2]]) as usize;
   122→            let frame_type = self.buffer[3];
   123→            let flags = self.buffer[4];
   124→            let stream_id = u32::from_be_bytes([
   125→                self.buffer[5] & 0x7F, // Clear reserved bit
   126→                self.buffer[6],
   127→                self.buffer[7],
   128→                self.buffer[8],
   129→            ]);
   130→
   131→            // Check if we have the complete frame
   132→            if self.buffer.len() < 9 + length {
   133→                break; // Wait for more data
   134→            }
   135→
   136→            // Extract frame payload (copy to avoid borrow issues)
   137→            let payload = self.buffer[9..9 + length].to_vec();
   138→
   139→            // Parse frame based on type
   140→            match frame_type {
   141→                0x00 => {
   142→                    // DATA frame
   143→                    let end_stream = (flags & 0x01) != 0;
   144→                    events.push(H2Event::Data {
   145→                        stream_id,
   146→                        data: Bytes::copy_from_slice(&payload),
   147→                        end_stream,
   148→                    });
   149→                }
   150→                0x01 => {
   151→                    // HEADERS frame
   152→                    let end_stream = (flags & 0x01) != 0;
   153→                    let end_headers = (flags & 0x04) != 0;
   154→
   155→                    if !end_headers {
   156→                        // Start accumulating header block fragments
   157→                        self.header_block_buffer = Some((stream_id, payload.clone(), end_stream));
   158→                    } else {
   159→                        // Complete header block in one frame
   160→                        let headers = match self.parse_hpack_headers(&payload) {
   161→                            Ok(h) => h,
   162→                            Err(e) => {
   163→                                // HPACK degradation - log warning and continue
   164→                                if !self.hpack_degraded {
   165→                                    self.hpack_degraded = true;
   166→                                    tracing::warn!("HPACK degradation: {}", e);
   167→                                    events.push(H2Event::HpackDegraded {
   168→                                        reason: e.to_string(),
   169→                                    });
   170→                                }
   171→                                HashMap::new()
   172→                            }
   173→                        };
   174→
   175→                        events.push(H2Event::Headers {
   176→                            stream_id,
   177→                            headers,
   178→                            end_stream,
   179→                        });
   180→                    }
   181→                }
   182→                0x09 => {
   183→                    // CONTINUATION frame
   184→                    let end_headers = (flags & 0x04) != 0;
   185→
   186→                    if let Some((buffered_stream_id, mut buffer, buffered_end_stream)) =
   187→                        self.header_block_buffer.take()
   188→                    {
   189→                        if buffered_stream_id == stream_id {
   190→                            // Append to buffer
   191→                            buffer.extend_from_slice(&payload);
   192→
   193→                            if end_headers {
   194→                                // Complete header block - parse it
   195→                                let headers = match self.parse_hpack_headers(&buffer) {
   196→                                    Ok(h) => h,
   197→                                    Err(e) => {
   198→                                        if !self.hpack_degraded {
   199→                                            self.hpack_degraded = true;
   200→                                            tracing::warn!("HPACK degradation: {}", e);
   201→                                            events.push(H2Event::HpackDegraded {
   202→                                                reason: e.to_string(),
   203→                                            });
   204→                                        }
   205→                                        HashMap::new()
   206→                                    }
   207→                                };
   208→
   209→                                events.push(H2Event::Headers {
   210→                                    stream_id,
   211→                                    headers,
   212→                                    end_stream: buffered_end_stream,
   213→                                });
   214→                            } else {
   215→                                // Still accumulating - put buffer back
   216→                                self.header_block_buffer = Some((buffered_stream_id, buffer, buffered_end_stream));
   217→                            }
   218→                        } else {
   219→                            // Stream ID mismatch - protocol error, clear buffer
   220→                            tracing::warn!(
   221→                                "CONTINUATION frame stream ID mismatch: expected {}, got {}",
   222→                                buffered_stream_id,
   223→                                stream_id
   224→                            );
   225→                        }
   226→                    } else {
   227→                        // CONTINUATION without HEADERS - protocol error, ignore
   228→                        tracing::warn!("CONTINUATION frame without preceding HEADERS");
   229→                    }
   230→                }
   231→                0x04 => {
   232→                    // SETTINGS frame
   233→                    events.push(H2Event::Settings);
   234→                }
   235→                0x03 => {
   236→                    // RST_STREAM frame
   237→                    events.push(H2Event::RstStream { stream_id });
   238→                }
   239→                0x07 => {
   240→                    // GOAWAY frame
   241→                    events.push(H2Event::GoAway);
   242→                }
   243→                _ => {
   244→                    // Unknown frame type - skip
   245→                    tracing::debug!("Skipping unknown HTTP/2 frame type: 0x{:02x}", frame_type);
   246→                }
   247→            }
   248→
   249→            // Remove parsed frame from buffer
   250→            self.buffer.drain(0..9 + length);
   251→        }
   252→
   253→        Ok(events)
   254→    }
   255→
   256→    /// Parse HPACK-encoded headers.
   257→    ///
   258→    /// This is a simplified implementation that handles literal headers without indexing.
   259→    /// In production, this should use h2-sans-io's HPACK decoder.
   260→    fn parse_hpack_headers(&mut self, data: &[u8]) -> Result<HashMap<String, String>, GrpcError> {
   261→        let mut headers = HashMap::new();
   262→        let mut offset = 0;
   263→
   264→        while offset < data.len() {
   265→            let byte = data[offset];
   266→
   267→            // Check for indexed header (0x80 prefix, 7-bit index)
   268→            if (byte & 0x80) != 0 {
   269→                let (index, index_bytes) = self.parse_integer(&data[offset..], 7)?;
   270→                offset += index_bytes;
   271→
   272→                // Static table lookup
   273→                if let Some((name, value)) = self.static_table_lookup(index) {
   274→                    headers.insert(name.to_string(), value.to_string());
   275→                } else {
   276→                    // Dynamic table reference - requires context we may not have
   277→                    return Err(GrpcError::HpackError(format!(
   278→                        "Dynamic table reference {} not available (mid-stream capture)",
   279→                        index
   280→                    )));
   281→                }
   282→            }
   283→            // Check for literal header with incremental indexing (0x40 prefix, 6-bit index)
   284→            else if (byte & 0x40) != 0 {
   285→                let (name_index, name_index_bytes) = self.parse_integer(&data[offset..], 6)?;
   286→                offset += name_index_bytes;
   287→
   288→                // If name_index == 0, name is literal; otherwise it's from table
   289→                let name = if name_index == 0 {
   290→                    // Literal name
   291→                    if offset >= data.len() {
   292→                        break;
   293→                    }
   294→                    let (name_len, name_len_bytes) = self.parse_integer(&data[offset..], 7)?;
   295→                    offset += name_len_bytes;
   296→                    if offset + name_len > data.len() {
   297→                        break;
   298→                    }
   299→                    let name = String::from_utf8_lossy(&data[offset..offset + name_len]).to_string();
   300→                    offset += name_len;
   301→                    name
   302→                } else {
   303→                    // Indexed name from static table
   304→                    self.static_table_lookup(name_index)
   305→                        .map(|(n, _)| n.to_string())
   306→                        .unwrap_or_else(|| "unknown".to_string())
   307→                };
   308→
   309→                // Parse value (always literal)
   310→                if offset >= data.len() {
   311→                    break;
   312→                }
   313→                let (value_len, value_len_bytes) = self.parse_integer(&data[offset..], 7)?;
   314→                offset += value_len_bytes;
   315→                if offset + value_len > data.len() {
   316→                    break;
   317→                }
   318→                let value = String::from_utf8_lossy(&data[offset..offset + value_len]).to_string();
   319→                offset += value_len;
   320→
   321→                headers.insert(name, value);
   322→            }
   323→            // Check for dynamic table size update (0x20 prefix, 5-bit value)
   324→            else if (byte & 0xE0) == 0x20 {
   325→                let (_new_size, size_bytes) = self.parse_integer(&data[offset..], 5)?;
   326→                offset += size_bytes;
   327→                // We don't maintain a dynamic table, so just consume the bytes
   328→            }
   329→            // Check for literal header never indexed (0x10 prefix, 4-bit index)
   330→            else if (byte & 0x10) != 0 {
   331→                let (name_index, name_index_bytes) = self.parse_integer(&data[offset..], 4)?;
   332→                offset += name_index_bytes;
   333→
   334→                // Same parsing as literal-with-indexing
   335→                let name = if name_index == 0 {
   336→                    if offset >= data.len() {
   337→                        break;
   338→                    }
   339→                    let (name_len, name_len_bytes) = self.parse_integer(&data[offset..], 7)?;
   340→                    offset += name_len_bytes;
   341→                    if offset + name_len > data.len() {
   342→                        break;
   343→                    }
   344→                    let name = String::from_utf8_lossy(&data[offset..offset + name_len]).to_string();
   345→                    offset += name_len;
   346→                    name
   347→                } else {
   348→                    self.static_table_lookup(name_index)
   349→                        .map(|(n, _)| n.to_string())
   350→                        .unwrap_or_else(|| "unknown".to_string())
   351→                };
   352→
   353→                if offset >= data.len() {
   354→                    break;
   355→                }
   356→                let (value_len, value_len_bytes) = self.parse_integer(&data[offset..], 7)?;
   357→                offset += value_len_bytes;
   358→                if offset + value_len > data.len() {
   359→                    break;
   360→                }
   361→                let value = String::from_utf8_lossy(&data[offset..offset + value_len]).to_string();
   362→                offset += value_len;
   363→
   364→                headers.insert(name, value);
   365→            }
   366→            // Check for literal header without indexing (0x00 prefix, 4-bit index)
   367→            else {
   368→                let (name_index, name_index_bytes) = self.parse_integer(&data[offset..], 4)?;
   369→                offset += name_index_bytes;
   370→
   371→                let name = if name_index == 0 {
   372→                    if offset >= data.len() {
   373→                        break;
   374→                    }
   375→                    let (name_len, name_len_bytes) = self.parse_integer(&data[offset..], 7)?;
   376→                    offset += name_len_bytes;
   377→                    if offset + name_len > data.len() {
   378→                        break;
   379→                    }
   380→                    let name = String::from_utf8_lossy(&data[offset..offset + name_len]).to_string();
   381→                    offset += name_len;
   382→                    name
   383→                } else {
   384→                    self.static_table_lookup(name_index)
   385→                        .map(|(n, _)| n.to_string())
   386→                        .unwrap_or_else(|| "unknown".to_string())
   387→                };
   388→
   389→                if offset >= data.len() {
   390→                    break;
   391→                }
   392→                let (value_len, value_len_bytes) = self.parse_integer(&data[offset..], 7)?;
   393→                offset += value_len_bytes;
   394→                if offset + value_len > data.len() {
   395→                    break;
   396→                }
   397→                let value = String::from_utf8_lossy(&data[offset..offset + value_len]).to_string();
   398→                offset += value_len;
   399→
   400→                headers.insert(name, value);
   401→            }
   402→        }
   403→
   404→        Ok(headers)
   405→    }
   406→
   407→    /// Parse HPACK integer with N-bit prefix.
   408→    /// Returns (value, bytes_consumed).
   409→    fn parse_integer(&self, data: &[u8], n: u8) -> Result<(usize, usize), GrpcError> {
   410→        if data.is_empty() {
   411→            return Err(GrpcError::HpackError("Unexpected end of data".to_string()));
   412→        }
   413→
   414→        let mask = (1u8 << n) - 1;
   415→        let mut value = (data[0] & mask) as usize;
   416→
   417→        if value < mask as usize {
   418→            return Ok((value, 1));
   419→        }
   420→
   421→        // Multi-byte integer
   422→        let mut offset = 1;
   423→        let mut m = 0;
   424→        loop {
   425→            if offset >= data.len() {
   426→                return Err(GrpcError::HpackError("Unexpected end of data".to_string()));
   427→            }
   428→
   429→            let byte = data[offset];
   430→            value += ((byte & 0x7F) as usize) << m;
   431→            m += 7;
   432→            offset += 1;
   433→
   434→            if (byte & 0x80) == 0 {
   435→                break;
   436→            }
   437→        }
   438→
   439→        Ok((value, offset))
   440→    }
   441→
   442→    /// Lookup in HTTP/2 static table (RFC 7541 Appendix A).
   443→    fn static_table_lookup(&self, index: usize) -> Option<(&'static str, &'static str)> {
   444→        match index {
   445→            1 => Some((":authority", "")),
   446→            2 => Some((":method", "GET")),
   447→            3 => Some((":method", "POST")),
   448→            4 => Some((":path", "/")),
   449→            5 => Some((":path", "/index.html")),
   450→            6 => Some((":scheme", "http")),
   451→            7 => Some((":scheme", "https")),
   452→            8 => Some((":status", "200")),
   453→            9 => Some((":status", "204")),
   454→            10 => Some((":status", "206")),
   455→            11 => Some((":status", "304")),
   456→            12 => Some((":status", "400")),
   457→            13 => Some((":status", "404")),
   458→            14 => Some((":status", "500")),
   459→            15 => Some(("accept-charset", "")),
   460→            16 => Some(("accept-encoding", "gzip, deflate")),
   461→            17 => Some(("accept-language", "")),
   462→            18 => Some(("accept-ranges", "")),
   463→            19 => Some(("accept", "")),
   464→            20 => Some(("access-control-allow-origin", "")),
   465→            21 => Some(("age", "")),
   466→            22 => Some(("allow", "")),
   467→            23 => Some(("authorization", "")),
   468→            24 => Some(("cache-control", "")),
   469→            25 => Some(("content-disposition", "")),
   470→            26 => Some(("content-encoding", "")),
   471→            27 => Some(("content-language", "")),
   472→            28 => Some(("content-length", "")),
   473→            29 => Some(("content-location", "")),
   474→            30 => Some(("content-range", "")),
   475→            31 => Some(("content-type", "")),
   476→            32 => Some(("cookie", "")),
   477→            33 => Some(("date", "")),
   478→            34 => Some(("etag", "")),
   479→            35 => Some(("expect", "")),
   480→            36 => Some(("expires", "")),
   481→            37 => Some(("from", "")),
   482→            38 => Some(("host", "")),
   483→            39 => Some(("if-match", "")),
   484→            40 => Some(("if-modified-since", "")),
   485→            41 => Some(("if-none-match", "")),
   486→            42 => Some(("if-range", "")),
   487→            43 => Some(("if-unmodified-since", "")),
   488→            44 => Some(("last-modified", "")),
   489→            45 => Some(("link", "")),
   490→            46 => Some(("location", "")),
   491→            47 => Some(("max-forwards", "")),
   492→            48 => Some(("proxy-authenticate", "")),
   493→            49 => Some(("proxy-authorization", "")),
   494→            50 => Some(("range", "")),
   495→            51 => Some(("referer", "")),
   496→            52 => Some(("refresh", "")),
   497→            53 => Some(("retry-after", "")),
   498→            54 => Some(("server", "")),
   499→            55 => Some(("set-cookie", "")),
   500→            56 => Some(("strict-transport-security", "")),
   501→            57 => Some(("transfer-encoding", "")),
   502→            58 => Some(("user-agent", "")),
   503→            59 => Some(("vary", "")),
   504→            60 => Some(("via", "")),
   505→            61 => Some(("www-authenticate", "")),
   506→            _ => None,
   507→        }
   508→    }
   509→
   510→    /// Get the state for a stream, creating it if it doesn't exist.
   511→    pub fn get_stream(&mut self, stream_id: u32) -> &mut StreamState {
   512→        self.streams.entry(stream_id).or_insert_with(StreamState::new)
   513→    }
   514→
   515→    /// Check if HPACK degradation has occurred.
   516→    pub fn is_hpack_degraded(&self) -> bool {
   517→        self.hpack_degraded
   518→    }
   519→}
   520→
   521→impl Default for H2Codec {
   522→    fn default() -> Self {
   523→        Self::new()
