     1→//! gRPC Length-Prefixed-Message (LPM) parsing.
     2→//!
     3→//! gRPC uses a 5-byte header followed by the message payload:
     4→//! - 1 byte: compressed flag (0 = uncompressed, 1 = compressed)
     5→//! - 4 bytes: message length (big-endian u32)
     6→//! - N bytes: message payload
     7→//!
     8→//! Messages may span multiple HTTP/2 DATA frames.
     9→
    10→use crate::error::GrpcError;
    11→use bytes::Bytes;
    12→use std::io::Read;
    13→
    14→/// gRPC compression algorithm.
    15→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    16→pub enum CompressionAlgorithm {
    17→    /// No compression (identity).
    18→    Identity,
    19→    /// gzip compression.
    20→    Gzip,
    21→    /// deflate compression.
    22→    Deflate,
    23→}
    24→
    25→impl CompressionAlgorithm {
    26→    /// Parse compression algorithm from gRPC `grpc-encoding` header value.
    27→    pub fn from_header(value: &str) -> Self {
    28→        match value {
    29→            "gzip" => Self::Gzip,
    30→            "deflate" => Self::Deflate,
    31→            _ => Self::Identity,
    32→        }
    33→    }
    34→}
    35→
    36→/// A parsed gRPC message.
    37→#[derive(Debug, Clone)]
    38→pub struct GrpcMessage {
    39→    /// The decompressed message payload.
    40→    pub payload: Bytes,
    41→}
    42→
    43→/// Parser for gRPC Length-Prefixed-Messages.
    44→///
    45→/// Handles message accumulation across multiple DATA frames.
    46→pub struct LpmParser {
    47→    /// Buffer for accumulating partial message data.
    48→    buffer: Vec<u8>,
    49→    /// Expected compression algorithm from grpc-encoding header.
    50→    compression: CompressionAlgorithm,
    51→}
    52→
    53→impl LpmParser {
    54→    /// Create a new LPM parser with the given compression algorithm.
    55→    pub fn new(compression: CompressionAlgorithm) -> Self {
    56→        Self {
    57→            buffer: Vec::new(),
    58→            compression,
    59→        }
    60→    }
    61→
    62→    /// Feed data into the parser and extract complete messages.
    63→    ///
    64→    /// Returns a vector of complete messages. Incomplete messages are buffered
    65→    /// internally and will be returned on subsequent calls.
    66→    pub fn feed(&mut self, data: &[u8]) -> Result<Vec<GrpcMessage>, GrpcError> {
    67→        // Append new data to buffer
    68→        self.buffer.extend_from_slice(data);
    69→
    70→        let mut messages = Vec::new();
    71→
    72→        // Parse complete messages from buffer
    73→        loop {
    74→            // Need at least 5 bytes for the LPM header
    75→            if self.buffer.len() < 5 {
    76→                break;
    77→            }
    78→
    79→            // Read LPM header
    80→            let compressed_flag = self.buffer[0];
    81→            let message_length = u32::from_be_bytes([
    82→                self.buffer[1],
    83→                self.buffer[2],
    84→                self.buffer[3],
    85→                self.buffer[4],
    86→            ]) as usize;
    87→
    88→            // Check if we have the complete message
    89→            let total_length = 5 + message_length;
    90→            if self.buffer.len() < total_length {
    91→                // Message incomplete, wait for more data
    92→                break;
    93→            }
    94→
    95→            // Extract message payload
    96→            let payload_bytes = self.buffer[5..total_length].to_vec();
    97→
    98→            // Remove parsed message from buffer
    99→            self.buffer.drain(0..total_length);
   100→
   101→            // Decompress if needed
   102→            let payload = if compressed_flag == 1 {
   103→                self.decompress(&payload_bytes)?
   104→            } else {
   105→                Bytes::from(payload_bytes)
   106→            };
   107→
   108→            messages.push(GrpcMessage { payload });
   109→        }
   110→
   111→        Ok(messages)
   112→    }
   113→
   114→    /// Decompress a payload using the configured compression algorithm.
   115→    fn decompress(&self, data: &[u8]) -> Result<Bytes, GrpcError> {
   116→        match self.compression {
   117→            CompressionAlgorithm::Identity => Ok(Bytes::copy_from_slice(data)),
   118→            CompressionAlgorithm::Gzip => {
   119→                let mut decoder = flate2::read::GzDecoder::new(data);
   120→                let mut decompressed = Vec::new();
   121→                decoder
   122→                    .read_to_end(&mut decompressed)
   123→                    .map_err(|e| GrpcError::DecompressionError(e.to_string()))?;
   124→                Ok(Bytes::from(decompressed))
   125→            }
   126→            CompressionAlgorithm::Deflate => {
   127→                // gRPC "deflate" is actually zlib (RFC 1950), not raw deflate (RFC 1951)
   128→                let mut decoder = flate2::read::ZlibDecoder::new(data);
   129→                let mut decompressed = Vec::new();
   130→                decoder
   131→                    .read_to_end(&mut decompressed)
   132→                    .map_err(|e| GrpcError::DecompressionError(e.to_string()))?;
   133→                Ok(Bytes::from(decompressed))
   134→            }
   135→        }
   136→    }
   137→
   138→}
   139→
   140→#[cfg(test)]
   141→mod tests {
   142→    use super::*;
   143→
   144→    #[test]
   145→    fn test_lpm_single_message() {
   146→        let mut parser = LpmParser::new(CompressionAlgorithm::Identity);
   147→
   148→        // Create a test message: compressed=0, length=5, payload="hello"
   149→        let mut data = vec![0u8]; // compressed flag
   150→        data.extend_from_slice(&5u32.to_be_bytes()); // length
   151→        data.extend_from_slice(b"hello"); // payload
   152→
   153→        let messages = parser.feed(&data).unwrap();
   154→        assert_eq!(messages.len(), 1);
   155→        assert_eq!(&messages[0].payload[..], b"hello");
   156→    }
   157→
   158→    #[test]
   159→    fn test_lpm_multi_frame() {
   160→        let mut parser = LpmParser::new(CompressionAlgorithm::Identity);
   161→
   162→        // Create a test message split across two frames
   163→        let mut frame1 = vec![0u8]; // compressed flag
   164→        frame1.extend_from_slice(&10u32.to_be_bytes()); // length
   165→        frame1.extend_from_slice(b"hello"); // partial payload
   166→
   167→        let frame2 = b"world"; // rest of payload
   168→
   169→        // Feed first frame - should not produce a message yet
   170→        let messages = parser.feed(&frame1).unwrap();
   171→        assert_eq!(messages.len(), 0);
   172→
   173→        // Feed second frame - should produce complete message
   174→        let messages = parser.feed(frame2).unwrap();
   175→        assert_eq!(messages.len(), 1);
   176→        assert_eq!(&messages[0].payload[..], b"helloworld");
   177→    }
   178→
   179→    #[test]
   180→    fn test_lpm_multiple_messages() {
   181→        let mut parser = LpmParser::new(CompressionAlgorithm::Identity);
   182→
   183→        // Create two messages in one buffer
   184→        let mut data = Vec::new();
   185→
   186→        // Message 1: "hi"
   187→        data.push(0u8);
   188→        data.extend_from_slice(&2u32.to_be_bytes());
   189→        data.extend_from_slice(b"hi");
   190→
   191→        // Message 2: "bye"
   192→        data.push(0u8);
   193→        data.extend_from_slice(&3u32.to_be_bytes());
   194→        data.extend_from_slice(b"bye");
   195→
   196→        let messages = parser.feed(&data).unwrap();
   197→        assert_eq!(messages.len(), 2);
   198→        assert_eq!(&messages[0].payload[..], b"hi");
   199→        assert_eq!(&messages[1].payload[..], b"bye");
   200→    }
   201→}
